            CREATE OR REPLACE FUNCTION sync_module_study_group_class_to_study_group_class()
            RETURNS TRIGGER AS $$
            BEGIN
                IF pg_trigger_depth() > 1 THEN
                    IF (TG_OP = 'DELETE') THEN
                        RETURN OLD;
                    END IF;
                    RETURN NEW;
                END IF;

                IF (TG_OP = 'INSERT') THEN
                    INSERT INTO study_group_class (
                        study_group_class_id, name, study_id, owner_id,
                        date_created, date_updated, update_id,
                        group_class_type_id, status_id, subject_assignment
                    )
                    VALUES (
                        NEW.study_group_class_id, NEW.name, NEW.study_id, NEW.owner_id,
                        NEW.date_created, NEW.date_updated, NEW.update_id,
                        NEW.group_class_type_id, NEW.status_id, NEW.subject_assignment
                    )
                    ON CONFLICT (study_group_class_id) DO UPDATE SET
                        name = EXCLUDED.name,
                        study_id = EXCLUDED.study_id,
                        owner_id = EXCLUDED.owner_id,
                        date_created = EXCLUDED.date_created,
                        date_updated = EXCLUDED.date_updated,
                        update_id = EXCLUDED.update_id,
                        group_class_type_id = EXCLUDED.group_class_type_id,
                        status_id = EXCLUDED.status_id,
                        subject_assignment = EXCLUDED.subject_assignment;
                    RETURN NEW;
                ELSIF (TG_OP = 'UPDATE') THEN
                    UPDATE study_group_class SET
                        name = NEW.name,
                        study_id = NEW.study_id,
                        owner_id = NEW.owner_id,
                        date_created = NEW.date_created,
                        date_updated = NEW.date_updated,
                        update_id = NEW.update_id,
                        group_class_type_id = NEW.group_class_type_id,
                        status_id = NEW.status_id,
                        subject_assignment = NEW.subject_assignment
                    WHERE study_group_class_id = OLD.study_group_class_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'DELETE') THEN
                    DELETE FROM study_group_class WHERE study_group_class_id = OLD.study_group_class_id;
                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            CREATE OR REPLACE FUNCTION sync_module_study_group_to_study_group()
            RETURNS TRIGGER AS $$
            BEGIN
                IF pg_trigger_depth() > 1 THEN
                    IF (TG_OP = 'DELETE') THEN
