                    VALUES (
                        NEW.study_group_id, NEW.name, NEW.description, NEW.study_group_class_id
                    )
                    ON CONFLICT (study_group_id) DO UPDATE SET
                        name = EXCLUDED.name,
                        description = EXCLUDED.description,
                        study_group_class_id = EXCLUDED.study_group_class_id;
