            END;
            $$ LANGUAGE plpgsql;

            DROP TRIGGER IF EXISTS trg_sync_study_group_class_to_module ON study_group_class;
            CREATE TRIGGER trg_sync_study_group_class_to_module
            AFTER INSERT OR UPDATE OR DELETE ON study_group_class
            FOR EACH ROW EXECUTE FUNCTION sync_study_group_class_to_module_study_group_class();

            CREATE OR REPLACE FUNCTION sync_study_group_to_module_study_group()
            RETURNS TRIGGER AS $$
            BEGIN
                IF pg_trigger_depth() > 1 THEN
