            DROP TRIGGER IF EXISTS trg_sync_study_group_to_module ON study_group;
            CREATE TRIGGER trg_sync_study_group_to_module
            AFTER INSERT OR UPDATE OR DELETE ON study_group
            FOR EACH ROW EXECUTE FUNCTION sync_study_group_to_module_study_group();

